from flask import Flask, jsonify, request
from functools import wraps
import jwt

app = Flask(__name__)
SECRET_KEY = 'YOUR-SECRET-KEY'  # replace with your secret key
TOKEN_DB = {}  # for testing, replace this with a real database

def require_oauth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth = request.headers.get('Authorization')
        
        if not auth:
            return jsonify({'message': 'Missing Authorization Header'}), 401
            
        bearer = auth.split()
        
        if len(bearer) != 2 or bearer[0].lower() != "bearer":
            return jsonify({'message': 'Invalid Authorization format'}), 401
                
        token = bearer[1]
        
        try:
            jwt.decode(token, SECRET_KEY)
        except Exception as e:
            print(e)
            return jsonify({'message': 'Invalid Token'}), 403
            
        if token not in TOKEN_DB:
            return jsonify({'message': 'Token not found'}), 401
                
        return f(*args, **kwargs)
    return decorated

@app.route('/protected')
@require_oauth
def protected_endpoint():
    return jsonify({"message": "You have accessed a protected endpoint!"})

if __name__ == '__main__':
    app.run(debug=True)